import tiktoken
from autogen import register_function

class TokenBudgetMonitor:
    def __init__(self, budget=50000):
        self.budget = budget
        self.total_tokens = 0
        self.encoding = tiktoken.get_encoding("cl100k_base")

    def check_usage(self, message):
        msg_tokens = len(self.encoding.encode(message["content"]))
        self.total_tokens += msg_tokens

        if self.total_tokens > self.budget * 0.8:
            return {
                "alert": "Token budget approaching limit",
                "usage_pct": (self.total_tokens / self.budget) * 100,
                "remaining": self.budget - self.total_tokens
            }
        return None

# Usage in agent
monitor = TokenBudgetMonitor()

def reply_monitor(sender, config):
    alert = monitor.check_usage({"content": sender.last_message()["content"]})
    if alert:
        print(f"COST ALERT: {alert}")
    return sender.generate_reply(config)

from difflib import SequenceMatcher
import autogen

def detect_redundant_responses(messages, threshold=0.7):
    if len(messages) < 2:
        return False

    contents = [msg["content"] for msg in messages[-2:]]
    similarity = SequenceMatcher(None, contents[0], contents[1]).ratio()

    return {
        "is_redundant": similarity > threshold,
        "similarity_score": similarity,
        "agents_involved": [msg.get("agent_name", "unknown") for msg in messages[-2:]]
    }

# Integrate as reply filter
def redundancy_filter(sender, config):
    history = sender.chat_messages[sender]["messages"]
    redundancy = detect_redundant_responses(history)
    if redundancy["is_redundant"]:
        print(f"REDUNDANCY DETECTED: {redundancy}")
        return "[REDUNDANT_RESPONSE_SKIPPED]"
    return sender.generate_reply(config)
